import React from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const navItems = [
  { path: '/dashboard', icon: 'fa-home', label: 'Dashboard' },
  { path: '/alumni', icon: 'fa-users', label: 'Alumni Network' },
  { path: '/jobs', icon: 'fa-briefcase', label: 'Jobs & Internships' },
  { path: '/forum', icon: 'fa-comments', label: 'Discussion Forum' },
  { path: '/events', icon: 'fa-calendar', label: 'Events' },
  { path: '/messages', icon: 'fa-envelope', label: 'Messages' },
  { path: '/mentorship', icon: 'fa-hands-helping', label: 'Mentorship' },
  { path: '/profile', icon: 'fa-user-circle', label: 'My Profile' },
];

const Sidebar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const initials = user?.fullName?.split(' ').map(n => n[0]).join('').toUpperCase() || 'U';

  return (
    <div className="sidebar">
      <div className="sidebar-logo">
        Alumni<span>Connect</span>
      </div>
      <nav className="sidebar-nav">
        {navItems.map(item => (
          <NavLink
            key={item.path}
            to={item.path}
            className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}
          >
            <i className={`fas ${item.icon}`}></i>
            {item.label}
          </NavLink>
        ))}
        <div className="nav-item" onClick={handleLogout} style={{ cursor: 'pointer', marginTop: 'auto' }}>
          <i className="fas fa-sign-out-alt"></i>
          Logout
        </div>
      </nav>
      <div className="sidebar-user">
        <div className="avatar">{initials}</div>
        <div>
          <div style={{ fontWeight: 600, fontSize: '0.85rem' }}>{user?.fullName}</div>
          <div style={{ fontSize: '0.75rem', opacity: 0.7 }}>{user?.role}</div>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;
